async function createGraphSubscription(accessToken, notificationUrl, resource, changeType, clientState, expiryMinutes) {
  const expirationDateTime = new Date(
    Date.now() + expiryMinutes * 60 * 1e3
  ).toISOString();
  const response = await fetch(`${GRAPH_API_BASE}/subscriptions`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${accessToken}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      changeType,
      notificationUrl,
      resource,
      expirationDateTime,
      clientState
    })
  });
  if (!response.ok) {
    const error = await response.text();
    throw new Error(`Graph subscription failed: ${error}`);
  }
  return response.json();
}
