function copyToClipboard(text6) {
  try {
    const platform = process.platform;
    if (platform === "darwin") {
      execSync("pbcopy", { input: text6 });
      return true;
    } else if (platform === "linux") {
      try {
        execSync("xclip -selection clipboard", { input: text6 });
        return true;
      } catch {
        try {
          execSync("xsel --clipboard --input", { input: text6 });
          return true;
        } catch {
          return false;
        }
      }
    } else if (platform === "win32") {
      execSync("clip", { input: text6 });
      return true;
    }
    return false;
  } catch {
    return false;
  }
}
