// src/utils/subscription.ts
async function runWebhookSubscription(cwd, pluginId) {
  const microsoftPluginRunner = {
    outlook: "runOutlookSubscribe",
    sharepoint: "runSharepointSubscribe",
    teams: "runTeamsSubscribe",
    onedrive: "runOnedriveSubscribe"
  };
  if (pluginId in microsoftPluginRunner) {
    const mod = await Promise.resolve().then(() => (init_subscribe_microsoft(), subscribe_microsoft_exports));
    const fn = mod[microsoftPluginRunner[pluginId]];
    if (typeof fn === "function") {
      await fn({ cwd });
      return;
    }
  }
  if (["gmail", "googledrive", "googlecalendar", "googlesheets"].includes(
    pluginId
  )) {
    const { runGoogleSubscribe: runGoogleSubscribe2 } = await Promise.resolve().then(() => (init_subscribe_google(), subscribe_google_exports));
    await runGoogleSubscribe2({ cwd, pluginId });
    return;
  }
  console.error(
    `[#corsair]: Webhook subscription not supported for plugin '${pluginId}'.`
  );
  process.exit(1);
}

// src/commands/base.command.ts
import { Option } from "commander";
var BaseCommand = class {
  action({}) {
  }
  getAliases() {
    return [];
  }
  getArguments() {
    return [];
  }
  getOptions() {
    return [];
  }
  getUsage() {
    return "";
  }
  getSubCommands() {
    return [];
  }
  /** When true, unknown flags (e.g. `--slack`) are passed through to the action. */
  allowUnknownOptions() {
    return false;
  }
  prepare = (program) => {
    const command = program.command(this.getName()).description(this.getDescription()).allowUnknownOption(this.allowUnknownOptions());
    const usage = this.getUsage();
    if (usage) {
      command.usage(usage);
    }
    this.getAliases().forEach((alias) => command.alias(alias));
    this.getOptions().forEach((option) => {
      const newOption = new Option(
        `${option.short}, ${option.long}`,
        option.description
      ).default(option.defaultValue);
      option.choices && option.choices.length > 0 && newOption.choices(option.choices);
      command.addOption(newOption);
    });
    this.getArguments().forEach(
      (argument) => command.argument(argument.name, argument.description)
    );
    command.action(async (...data) => {
      const argsCount = this.getArguments().length;
      const commandOptions = data[argsCount];
      const args = data.slice(0, argsCount);
      await this.action({ args, options: commandOptions });
    });
    this.getSubCommands().forEach((subCommand) => {
      subCommand.prepare(command);
    });
  };
};

// src/commands/auth.command.ts
var AuthCommand = class extends BaseCommand {
  getName() {
    return "auth";
  }
  getDescription() {
    return "Run plugin auth flows";
  }
  getOptions() {
    return [
      { short: "-p", long: "--plugin <id>", description: "Plugin id" },
      { short: "-t", long: "--tenant <id>", description: "Tenant id for auth" },
      {
        short: "-c",
        long: "--code <code>",
        description: "OAuth code to exchange"
      },
      {
        short: "-s",
        long: "--session <id>",
        description: "Session id for local auth state"
      },
      {
        short: "-C",
        long: "--credentials",
        description: "Show credential status"
      },
      {
        short: "-w",
        long: "--webhook",
        description: "Run webhook subscription setup"
      },
      {
        short: "-l",
        long: "--listen",
        description: "Listen for callback only"
      },
      {
        short: "-x",
        long: "--collect",
        description: "Collect auth response from listener"
      }
    ];
  }
  async action({ options }) {
    const cwd = process.cwd();
    if (options.webhook) {
      if (!options.plugin) {
        console.error("[#corsair]: --webhook requires --plugin=<id>.");
        process.exit(1);
      }
      await runWebhookSubscription(cwd, options.plugin);
      return;
    }
    const { runAuth: runAuth2 } = await Promise.resolve().then(() => (init_auth(), auth_exports));
    await runAuth2({
      cwd,
      pluginId: options.plugin,
      tenantId: options.tenant,
      code: options.code,
      credentials: options.credentials,
      listen: options.listen,
      collect: options.collect,
      sessionId: options.session
    });
  }
};

