// src/commands/script.command.ts
init_corsair_instance();
var AsyncFunction = Object.getPrototypeOf(async function() {
}).constructor;
var ScriptCommand = class extends BaseCommand {
  getName() {
    return "script";
  }
  getDescription() {
    return "Execute inline JavaScript with corsair injected";
  }
  getOptions() {
    return [
      {
        short: "-c",
        long: "--code <js>",
        description: "Async JavaScript body to execute"
      },
      {
        short: "-t",
        long: "--tenant <id>",
        description: "Tenant id for multi-tenant instances"
      }
    ];
  }
  async action({ options }) {
    const { code, tenant } = options;
    if (!code) {
      console.error('[#corsair]: Usage: corsair script --code "<js>"');
      process.exit(1);
    }
    let fn;
    try {
      fn = new AsyncFunction("corsair", code);
    } catch (error) {
      this.exitWithScriptError(error);
    }
    const instance = await getCorsairInstance({ cwd: process.cwd() });
    const client = resolveClient(instance, tenant);
    try {
      const result = await fn(client);
      if (result !== void 0) console.log(JSON.stringify(result, null, 2));
    } catch (error) {
      this.exitWithScriptError(error);
    }
  }
  exitWithScriptError(error) {
    const msg = error instanceof Error ? error.message : String(error);
    console.error(`[#corsair]: ${msg.slice(0, 500)}`);
    process.exit(1);
  }
};

