// src/lib/setup-credentials.ts
var SETUP_FLAGS_WITH_VALUE = /* @__PURE__ */ new Set(["--tenant", "-t", "--plugin", "-p"]);
function parseSetupCredentials(rawArgs, pluginIds) {
  const pluginSet = new Set(pluginIds);
  const result = {};
  let currentPlugin = null;
  for (let i = 0; i < rawArgs.length; i++) {
    const arg = rawArgs[i];
    if (arg === "--backfill" || arg === "-b" || arg === "-backfill") {
      continue;
    }
    if (SETUP_FLAGS_WITH_VALUE.has(arg)) {
      const value2 = rawArgs[++i];
      if (arg === "--plugin" || arg === "-p") {
        if (value2 && pluginSet.has(value2)) {
          currentPlugin = value2;
          result[value2] ??= {};
        }
      }
      continue;
    }
    if (arg.startsWith("--tenant=") || arg.startsWith("-t=")) {
      continue;
    }
    if (arg.startsWith("--plugin=")) {
      const pluginId = arg.slice("--plugin=".length);
      if (pluginSet.has(pluginId)) {
        currentPlugin = pluginId;
        result[pluginId] ??= {};
      }
      continue;
    }
    if (arg.startsWith("--")) {
      const flagBody = arg.slice(2);
      const eqIdx2 = flagBody.indexOf("=");
      if (eqIdx2 > 0) {
        const name = flagBody.slice(0, eqIdx2);
        const value2 = flagBody.slice(eqIdx2 + 1);
        if (name === "plugin" && pluginSet.has(value2)) {
          currentPlugin = value2;
          result[value2] ??= {};
        }
        continue;
      }
      if (pluginSet.has(flagBody)) {
        currentPlugin = flagBody;
        result[flagBody] ??= {};
      }
      continue;
    }
    const eqIdx = arg.indexOf("=");
    if (eqIdx <= 0) continue;
    const field = arg.slice(0, eqIdx);
    const value = arg.slice(eqIdx + 1);
    if (!field || !value || !currentPlugin) continue;
    const bucket = result[currentPlugin] ??= {};
    bucket[field] = value;
  }
  return result;
}
function getSetupRawArgs(argv = process.argv) {
  const setupIdx = argv.indexOf("setup");
  return setupIdx >= 0 ? argv.slice(setupIdx + 1) : [];
}

// src/commands/setup.command.ts
init_corsair();
init_corsair_instance();
var SetupCommand = class extends BaseCommand {
  allowUnknownOptions() {
    return true;
  }
  getName() {
    return "setup";
  }
  getDescription() {
    return "Initialize Corsair and set plugin credentials";
  }
  getOptions() {
    return [
      {
        short: "-b",
        long: "--backfill",
        description: "Seed data while initializing"
      },
      {
        short: "-t",
        long: "--tenant <id>",
        description: "Tenant id for multi-tenant setup"
      },
      {
        short: "-p",
        long: "--plugin <id>",
        description: "Plugin id for credentials"
      }
    ];
  }
  getArguments() {
    return [
      {
        name: "[credentials...]",
        description: "Credential pairs like key=value"
      }
    ];
  }
  async action({ options }) {
    const cwd = process.cwd();
    const backfill = options.backfill || this.hasLegacyBackfillFlag();
    const tenantId = options.tenant;
    const instance = await getCorsairInstance({ cwd });
    const internal = await extractInternalConfig(cwd);
    const credentials = parseSetupCredentials(
      getSetupRawArgs(),
      internal.plugins.map((p13) => p13.id)
    );
    await setupCorsair(instance, {
      backfill,
      tenantId,
      credentials,
      caller: "cli"
    });
  }
  hasLegacyBackfillFlag() {
    const setupIdx = process.argv.indexOf("setup");
    const rawArgs = setupIdx >= 0 ? process.argv.slice(setupIdx + 1) : [];
    return rawArgs.some((arg) => arg === "-backfill");
  }
};

// src/commands/studio.command.ts
import path4 from "path";
var StudioCommand = class extends BaseCommand {
  getName() {
    return "ui";
  }
  getAliases() {
    return ["studio"];
  }
  getDescription() {
    return "Start Corsair Studio";
  }
  getOptions() {
    return [
      {
        short: "-p",
        long: "--port <number>",
        description: "Port to start Studio on"
      },
      { short: "-o", long: "--open", description: "Open browser on launch" },
      {
        short: "-O",
        long: "--no-open",
        description: "Do not open browser on launch"
      }
    ];
  }
  async action({ options }) {
    const cwd = process.cwd();
    const port = options.port ? Number.parseInt(options.port, 10) : void 0;
    let startStudio;
    try {
      const { createRequire } = await import("module");
      const { pathToFileURL } = await import("url");
      const req = createRequire(path4.join(cwd, "package.json"));
      const resolvedPath = req.resolve("@corsair-dev/studio/server");
      const mod = await import(pathToFileURL(resolvedPath).href);
      const candidate = mod.start ?? mod.startStudio;
      if (!candidate) {
        throw new Error("@corsair-dev/studio/server did not export `start`.");
      }
      startStudio = candidate;
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error);
      if (msg.includes("Cannot find package") || msg.includes("Cannot find module") || msg.includes("ERR_MODULE_NOT_FOUND") || msg.includes("MODULE_NOT_FOUND")) {
        console.error("[#corsair]: Corsair Studio is not installed.");
        console.error(
          "[#corsair]: Install it with: pnpm add -D @corsair-dev/studio"
        );
        process.exit(1);
      }
      throw error;
    }
    await startStudio({ cwd, port, open: options.open });
    await new Promise((resolve) => {
      const shutdown = () => resolve();
      process.once("SIGINT", shutdown);
      process.once("SIGTERM", shutdown);
    });
  }
};

