// src/commands/subscribe.command.ts
var SubscribeCommand = class extends BaseCommand {
  getName() {
    return "subscribe";
  }
  getDescription() {
    return "Subscribe to various kinds of webhooks";
  }
  getOptions() {
    return [
      {
        short: "-p",
        long: "--plugin <id>",
        description: "Plugin id (legacy: prefer `corsair subscribe <plugin>`)"
      }
    ];
  }
  getSubCommands() {
    return [
      new SharepointCommand(),
      new TeamsCommand(),
      new OutlookCommand(),
      new OnedriveCommand()
    ];
  }
  async action({ options }) {
    if (!options.plugin) {
      console.error(
        "Usage: corsair subscribe --plugin=<id> or corsair subscribe <plugin>"
      );
      console.error(
        "[#corsair]: Supported: outlook, sharepoint, teams, onedrive"
      );
      process.exit(1);
    }
    if (options.plugin === "outlook") {
      const { runOutlookSubscribe: runOutlookSubscribe2 } = await Promise.resolve().then(() => (init_subscribe_microsoft(), subscribe_microsoft_exports));
      await runOutlookSubscribe2({ cwd: process.cwd() });
      return;
    }
    if (options.plugin === "sharepoint") {
      const { runSharepointSubscribe: runSharepointSubscribe2 } = await Promise.resolve().then(() => (init_subscribe_microsoft(), subscribe_microsoft_exports));
      await runSharepointSubscribe2({ cwd: process.cwd() });
      return;
    }
    if (options.plugin === "teams") {
      const { runTeamsSubscribe: runTeamsSubscribe2 } = await Promise.resolve().then(() => (init_subscribe_microsoft(), subscribe_microsoft_exports));
      await runTeamsSubscribe2({ cwd: process.cwd() });
      return;
    }
    if (options.plugin === "onedrive") {
      const { runOnedriveSubscribe: runOnedriveSubscribe2 } = await Promise.resolve().then(() => (init_subscribe_microsoft(), subscribe_microsoft_exports));
      await runOnedriveSubscribe2({ cwd: process.cwd() });
      return;
    }
    console.error(
      `[#corsair]: Unknown plugin for subscribe: '${options.plugin}'. Supported: outlook, sharepoint, teams, onedrive`
    );
    process.exit(1);
  }
};

